interface ChessSquareProps {
  row: number;
  col: number;
  color: SquareColor;
  piece: Piece | null;
  square: string;
  isSelected: boolean;
  isValidMove: boolean;
  isValidCapture: boolean;
  isCheck: boolean;
  isLastMove: boolean;
  onClick: () => void;
  size?: number;
  showCoordinates?: boolean;
}

const ChessSquare: React.FC<ChessSquareProps> = ({
  row,
  col,
  color,
  piece,
  square,
  isSelected,
  isValidMove,
  isValidCapture,
  isCheck,
  isLastMove,
  onClick,
  size = 60,
  showCoordinates = true
}) => {
  const backgroundColor = color === 'light' ? 'bg-chess-light' : 'bg-chess-dark';
  const coordinates = `${String.fromCharCode(97 + col)}${8 - row}`;

  return (
    <motion.div
      className={`
        chess-square relative flex items-center justify-center cursor-pointer
        ${backgroundColor}
        ${isSelected ? 'highlighted' : ''}
        ${isValidMove ? 'valid-move' : ''}
        ${isValidCapture ? 'valid-capture' : ''}
        ${isCheck ? 'check' : ''}
        ${isLastMove ? 'last-move' : ''}
      `}
      style={{
        width: size,
        height: size
      }}
      onClick={onClick}
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.2 }}
      whileHover={{ scale: piece ? 1 : 1.02 }}
      whileTap={{ scale: 0.98 }}
    >
      {piece && (
        <ChessPiece
          piece={piece}
          isSelected={isSelected}
          size={size}
        />
      )}

      {showCoordinates && (
        <>
          {col === 0 && (
            <span
              className="absolute left-1 top-0 text-xs font-semibold opacity-70 pointer-events-none"
              style={{ color: color === 'light' ? '#b58863' : '#f0d9b5' }}
