import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import ChessSquare from './ChessSquare';
import type { PieceColor } from '../types/chess.types';

interface ChessBoardProps {
  board: Map<string, import('../types/chess.types').Piece | null>;
  turn: PieceColor;
  selectedSquare: string | null;
  validMoves: string[];
  lastMove?: { from: string; to: string };
  onSquareClick: (square: string) => void;
  isFlipped?: boolean;
  isSquareInCheck: (square: string) => boolean;
  size?: number;
}

const ChessBoard: React.FC<ChessBoardProps> = ({
  board,
  turn,
  selectedSquare,
  validMoves,
  lastMove,
  onSquareClick,
  isFlipped = false,
  isSquareInCheck,
  size = 480
}) => {
  const squareSize = size / 8;
  const rows = isFlipped ? [0, 1, 2, 3, 4, 5, 6, 7] : [0, 1, 2, 3, 4, 5, 6, 7];
  const cols = isFlipped ? [7, 6, 5, 4, 3, 2, 1, 0] : [0, 1, 2, 3, 4, 5, 6, 7];

  const getSquareColor = (row: number, col: number): 'light' | 'dark' => {
    return (row + col) % 2 === 0 ? 'light' : 'dark';
  };

  const getSquareName = (row: number, col: number): string => {
    const file = String.fromCharCode(97 + col);
    const rank = 8 - row;
    return `${file}${rank}`;
  };

  return (
    <motion.div
      className="rounded-lg overflow-hidden shadow-2xl"
      initial={{ scale: 0.9, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      transition={{ duration: 0.3 }}
    >
      <div
        className="grid grid-cols-8 border-4 border-amber-900 rounded-lg overflow-hidden"
        style={{
          width: size,
          height: size,
          boxShadow: '0 20px 60px rgba(0, 0, 0, 0.5)'
        }}
      >
        <AnimatePresence mode="popLayout">
          {rows.map((row) =>
            cols.map((col) => {
              const square = getSquareName(row, col);
              const piece = board.get(square) || null;
              const squareColor = getSquareColor(row, col);
              const isSelected = selectedSquare === square;
              const isValidMove = validMoves.includes(square) && !piece;
              const isValidCapture = validMoves.includes(square) && !!piece;
              const isCheck = isSquareInCheck(square);
              const isLastMoveSquare = lastMove && (lastMove.from === square || lastMove.to === square);

              return (
                <ChessSquare
                  key={square}
                  row={row}
                  col={col}
                  color={squareColor}
                  piece={piece}
                  square={square}
                  isSelected={isSelected}
                  isValidMove={isValidMove}
                  isValidCapture={isValidCapture}
                  isCheck={isCheck}
                  isLastMove={isLastMoveSquare}
                  onClick={() => onSquareClick(square)}
                  size={squareSize}
                  showCoordinates
                />
              );
            })
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

export default ChessBoard;

