import React, { useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import type { Move } from '../types/chess.types';

interface MoveHistoryProps {
  moves: Move[];
}

const MoveHistory: React.FC<MoveHistoryProps> = ({ moves }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [moves]);

  return (
    <motion.div
      className="glass-panel rounded-xl p-4 h-64 flex flex-col"
      initial={{ x: 20, opacity: 0 }}
      animate={{ x: 0, opacity: 1 }}
      transition={{ duration: 0.3, delay: 0.1 }}
    >
      <h3 className="text-lg font-semibold mb-3 text-gray-200">Move History</h3>
      <div
        ref={scrollRef}
        className="flex-1 overflow-y-auto custom-scrollbar pr-2"
      >
        {moves.length === 0 ? (
          <p className="text-gray-500 text-sm italic">No moves yet</p>
        ) : (
          <div className="space-y-1">
            {moves.reduce<JSX.Element[]>((acc, move, index) => {
              if (index % 2 === 0) {
