import React, { useState } from 'react';
import { motion } from 'framer-motion';

interface GameControlsProps {
  onNewGame: () => void;
  onUndo: () => void;
  onFlipBoard: () => void;
  onCopyFEN: () => void;
  canUndo: boolean;
  isGameOver: boolean;
}

const GameControls: React.FC<GameControlsProps> = ({
  onNewGame,
  onUndo,
  onFlipBoard,
  onCopyFEN,
  canUndo,
