     1→import { useState, useCallback, useEffect } from 'react';
     2→import { Chess, SQUARES } from 'chess.js';
     3→import type { Piece, PieceColor, PieceType, Move, GameStatus, ChessGameHookReturn } from '../types/chess.types';
     4→
     5→const fenToPiece = (fen: string | undefined): Piece | null => {
     6→  if (!fen || fen === '-') return null;
     7→
     8→  const color: PieceColor = fen === fen.toUpperCase() ? 'w' : 'b';
     9→  const type = fen.toLowerCase() as PieceType;
    10→
    11→  return { type, color };
    12→};
    13→
    14→const getPieceUnicode = (piece: Piece): string => {
    15→  const symbols: Record<PieceColor, Record<PieceType, string>> = {
    16→    w: { k: '♔', q: '♕', r: '♖', b: '♗', n: '♘', p: '♙' },
    17→    b: { k: '♚', q: '♛', r: '♜', b: '♝', n: '♞', p: '♟' }
    18→  };
    19→  return symbols[piece.color][piece.type];
    20→};
    21→
    22→export const useChessGame = (): ChessGameHookReturn => {
    23→  const [game] = useState(() => new Chess());
    24→  const [board, setBoard] = useState<Map<string, Piece | null>>(new Map());
    25→  const [turn, setTurn] = useState<PieceColor>('w');
    26→  const [selectedSquare, setSelectedSquare] = useState<string | null>(null);
    27→  const [validMoves, setValidMoves] = useState<string[]>([]);
    28→  const [moveHistory, setMoveHistory] = useState<Move[]>([]);
    29→  const [capturedPieces, setCapturedPieces] = useState<{
    30→    white: Piece[];
    31→    black: Piece[];
    32→  }>({ white: [], black: [] });
    33→  const [gameStatus, setGameStatus] = useState<GameStatus>('ongoing');
    34→  const [lastMove, setLastMove] = useState<{ from: string; to: string } | undefined>();
    35→
    36→  const updateBoardState = useCallback(() => {
    37→    const newBoard = new Map<string, Piece | null>();
    38→
    39→    Object.keys(SQUARES).forEach(square => {
    40→      const piece = game.get(square as any);
    41→      newBoard.set(square, fenToPiece(piece as any));
    42→    });
    43→
    44→    setBoard(newBoard);
    45→    setTurn(game.turn() as PieceColor);
    46→    setGameStatus(determineGameStatus());
    47→  }, [game]);
    48→
    49→  const determineGameStatus = (): GameStatus => {
    50→    if (game.isCheckmate()) return 'checkmate';
    51→    if (game.isStalemate()) return 'stalemate';
    52→    if (game.isDraw()) return 'draw';
    53→    if (game.isCheck()) return 'check';
    54→    return 'ongoing';
    55→  };
    56→
    57→  const selectSquare = useCallback((square: string) => {
    58→    const piece = board.get(square);
    59→
    60→    if (selectedSquare && validMoves.includes(square)) {
    61→      makeMove(selectedSquare, square);
    62→      return;
    63→    }
    64→
    65→    if (piece && piece.color === turn) {
    66→      setSelectedSquare(square);
    67→      const moves = game.moves({ square: square as any, verbose: true }) as any[];
    68→      setValidMoves(moves.map(m => m.to));
    69→    } else {
    70→      setSelectedSquare(null);
    71→      setValidMoves([]);
    72→    }
    73→  }, [selectedSquare, board, turn, validMoves, game]);
    74→
    75→  const makeMove = useCallback((from: string, to: string, promotion?: PieceType): boolean => {
    76→    try {
    77→      const move = game.move({
    78→        from,
    79→        to,
    80→        promotion: promotion || 'q'
    81→      });
    82→
    83→      if (!move) return false;
    84→
    85→      const newMove: Move = {
    86→        from: move.from,
    87→        to: move.to,
    88→        piece: fenToPiece(move.piece)!,
    89→        captured: move.captured ? fenToPiece(move.captured) : undefined,
    90→        promotion: move.promotion,
    91→        san: move.san
    92→      };
    93→
    94→      setMoveHistory(prev => [...prev, newMove]);
    95→      setLastMove({ from, to });
    96→
    97→      if (move.captured) {
    98→        const capturedPiece = fenToPiece(move.captured)!;
    99→        setCapturedPieces(prev => {
   100→          const color = capturedPiece.color === 'w' ? 'white' : 'black';
   101→          return {
   102→            ...prev,
   103→            [color]: [...prev[color], capturedPiece]
   104→          };
   105→        });
   106→      }
   107→
   108→      setSelectedSquare(null);
   109→      setValidMoves([]);
   110→      updateBoardState();
   111→
   112→      return true;
   113→    } catch (e) {
   114→      return false;
   115→    }
   116→  }, [game, updateBoardState]);
   117→
   118→  const undoMove = useCallback(() => {
   119→    const move = game.undo();
   120→    if (move) {
   121→      setMoveHistory(prev => prev.slice(0, -1));
   122→
   123→      if (move.captured) {
   124→        const capturedPiece = fenToPiece(move.captured)!;
   125→        setCapturedPieces(prev => {
   126→          const color = capturedPiece.color === 'w' ? 'white' : 'black';
   127→          return {
   128→            ...prev,
   129→            [color]: prev[color].slice(0, -1)
   130→          };
   131→        });
   132→      }
   133→
   134→      const lastMoveIndex = moveHistory.length - 2;
   135→      if (lastMoveIndex >= 0) {
   136→        const lastMoveRecord = moveHistory[lastMoveIndex];
   137→        setLastMove({ from: lastMoveRecord.from, to: lastMoveRecord.to });
   138→      } else {
   139→        setLastMove(undefined);
   140→      }
   141→
   142→      setSelectedSquare(null);
   143→      setValidMoves([]);
   144→      updateBoardState();
   145→    }
   146→  }, [game, moveHistory, updateBoardState]);
   147→
   148→  const resetGame = useCallback(() => {
   149→    game.reset();
   150→    setMoveHistory([]);
   151→    setCapturedPieces({ white: [], black: [] });
   152→    setSelectedSquare(null);
   153→    setValidMoves([]);
   154→    setLastMove(undefined);
   155→    updateBoardState();
   156→  }, [game, updateBoardState]);
   157→
   158→  const getPieceAt = useCallback((square: string): Piece | null => {
   159→    return board.get(square) || null;
   160→  }, [board]);
   161→
   162→  const isSquareInCheck = useCallback((square: string): boolean => {
   163→    const piece = board.get(square);
   164→    return piece?.type === 'k' && piece.color === turn && game.isCheck();
   165→  }, [board, turn, game]);
   166→
   167→  const isGameOver = useCallback((): boolean => {
